import React, { useState } from "react";

const TaskCard = ({
  title = "",
  description = "",
  priority = "",
  status = "",
  date = "",
  image,
  type = "full",
  className = "",
}) => {
  // Стан для контролю видимості меню
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const statusClass = status ? status.toLowerCase().replace(/\s+/g, "-") : "";
  const priorityClass = priority ? priority.toLowerCase() : "";

  return (
    <div
      className={`task-card ${className} ${
        type === "compact" ? "compact-card" : ""
      }`}
    >
      <div className="task-header">
        <div className="task-title-row">
          {status && <span className={`status-dot ${statusClass}`}></span>}
          <h3 className="task-title">{title}</h3>
        </div>

        {/* Контейнер для іконки та меню */}
        <div className="more-options-container">
          <div
            className="more-options"
            onClick={() => setIsMenuOpen(!isMenuOpen)}
          >
            <svg className="icon icon-three-dots">
              <use xlinkHref="images/icons/dashboard-icons.svg#icon-three-dots"></use>
            </svg>
          </div>

          {/* ВИПАДАЮЧЕ МЕНЮ (дизайн згідно з фото) */}
          {isMenuOpen && (
            <div className="task-actions-dropdown">
              <div className="action-item" onClick={() => setIsMenuOpen(false)}>
                Vital
              </div>
              <div className="action-item" onClick={() => setIsMenuOpen(false)}>
                Edit
              </div>
              <div className="action-item" onClick={() => setIsMenuOpen(false)}>
                Delete
              </div>
              <div className="action-item" onClick={() => setIsMenuOpen(false)}>
                Finish
              </div>
            </div>
          )}
        </div>
      </div>

      {/* ... решта task-content та task-footer залишається без змін ... */}
      <div className="task-content">
        <div className="task-text-info">
          <p className="task-description">{description}</p>
        </div>
        {image && (
          <div className="task-image-container">
            <img src={image} alt="task visual" className="task-card-img" />
          </div>
        )}
      </div>

      <div className="task-footer">
        {priority && (
          <div className="meta-item">
            <span className="meta-label">Priority:</span>
            <span className={`meta-value priority-${priorityClass}`}>
              {priority}
            </span>
          </div>
        )}
        {status && (
          <div className="meta-item">
            <span className="meta-label">Status:</span>
            <span className={`meta-value status-text-${statusClass}`}>
              {status}
            </span>
          </div>
        )}
        {date && <div className="meta-date">Created on: {date}</div>}
      </div>
    </div>
  );
};

export default TaskCard;
